<div class="card"><div class="card-head"><h3>Transaction History</h3></div><form method="get" action="<?= base_url('index.php') ?>" class="filter-form"><input type="hidden" name="route" value="transactions"><input type="text" name="type" placeholder="Type" value="<?= e($filters['type']) ?>"><input type="text" name="status" placeholder="Status" value="<?= e($filters['status']) ?>"><input type="date" name="date_from" value="<?= e($filters['date_from']) ?>"><input type="date" name="date_to" value="<?= e($filters['date_to']) ?>"><button class="btn btn-outline" type="submit">Filter</button></form><div class="table-wrap"><table><thead><tr><th>Reference</th><th>Type</th><th>Direction</th><th>Amount</th><th>Status</th><th>Date</th><th>Detail</th></tr></thead><tbody><?php foreach ($transactions as $tx): ?><tr><td><?= e($tx['reference_no']) ?></td><td><?= e(ucwords(str_replace('_', ' ', $tx['type']))) ?></td><td><?= e($tx['direction']) ?></td><td class="<?= $tx['direction']==='credit' ? 'text-success' : 'text-danger' ?>"><?= $tx['direction']==='credit' ? '+' : '-' ?><?= money((float)$tx['amount']) ?></td><td><span class="badge"><?= e($tx['status']) ?></span></td><td><?= e($tx['created_at']) ?></td><td><a href="<?= base_url('index.php?route=transaction/detail&id=' . (int)$tx['id']) ?>">View</a></td></tr><?php endforeach; ?><?php if (!$transactions): ?><tr><td colspan="7">No transactions found.</td></tr><?php endif; ?></tbody></table></div></div>
